-- =============================================================================
-- Mentor-Connect / PeerBridge — LOCAL MOCK/TEST DATABASE SEED (1000 users)
--
-- *** WARNING: This resets the local mock/test database. ***
-- *** It DROPS and recreates every table listed below.  DO NOT run against ***
-- *** production or any database whose data you want to keep.            ***
--
-- Install (see database/README or project docs):
--   dropdb --if-exists mentor_connect_mock
--   createdb mentor_connect_mock
--   psql mentor_connect_mock -f database/mentor_connect_mock_1000.sql
--
-- Contents
--   Product tables : districts, tags, users, requests, request_tags,
--                    reports, blocks
--   Practice tables: questions (Python/get_questions.py, find_matches.py),
--                    schedules (per-user availability rows)
--   Practice views : mentors      (SELECT mentor FROM mentors;)
--                    schedules_db (SELECT schedules FROM schedules_db;)
--   Extra columns  : users.location / available_times / languages /
--                    grade_level / teaching_style
--                    (from Python/migrations/001_practice_additive.sql)
--                    requests.request — nullable text mirror of the primary
--                    subject so analysis.py's `SELECT request FROM requests;`
--                    returns subject names.
--
-- Fixed demo records
--   User 1   student001@test.edu  (mentee,  district 2, "Mon 5pm" slot)
--   User 501 mentor501@test.edu   (mentor,  district 2, "Mon 5pm" slot)
--   User 951 both951@test.edu     (role "both")
--   All passwords: Password123!  (bcrypt hash stored below)
--   Question 1 / Request 1: user 1 asks for Math (Algebra); mentor 501 is a
--   full-score match; mentor 502 matches too but is blocked by user 1.
--
-- Deterministic data: generated arithmetically from row ids — regenerating
-- produces byte-identical data (except this file's fixed bcrypt constant).
-- =============================================================================

BEGIN;

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;

DROP VIEW IF EXISTS schedules_db;
DROP VIEW IF EXISTS mentors;
DROP TABLE IF EXISTS schedules CASCADE;
DROP TABLE IF EXISTS questions CASCADE;
DROP TABLE IF EXISTS request_tags CASCADE;
DROP TABLE IF EXISTS blocks CASCADE;
DROP TABLE IF EXISTS reports CASCADE;
DROP TABLE IF EXISTS requests CASCADE;
DROP TABLE IF EXISTS users CASCADE;
DROP TABLE IF EXISTS tags CASCADE;
DROP TABLE IF EXISTS districts CASCADE;

-- ---------------------------------------------------------------- schema --

CREATE TABLE districts (
    id          SERIAL PRIMARY KEY,
    name        TEXT NOT NULL,
    county      TEXT NOT NULL,
    type        TEXT NOT NULL DEFAULT 'unified',
    created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE tags (
    id          SERIAL PRIMARY KEY,
    name        TEXT NOT NULL,
    color       TEXT NOT NULL DEFAULT '#6366f1',
    created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE users (
    id              SERIAL PRIMARY KEY,
    email           TEXT NOT NULL UNIQUE,
    name            TEXT NOT NULL,
    password_hash   TEXT NOT NULL,
    role            TEXT NOT NULL DEFAULT 'mentee',
    district_id     INTEGER NOT NULL REFERENCES districts(id),
    bio             TEXT,
    subjects        TEXT[] NOT NULL DEFAULT '{}',
    is_verified     BOOLEAN NOT NULL DEFAULT true,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    -- additive practice columns (Python/migrations/001_practice_additive.sql)
    location        TEXT,
    available_times TEXT[],
    languages       TEXT[],
    grade_level     TEXT,
    teaching_style  TEXT
);

CREATE TABLE requests (
    id              SERIAL PRIMARY KEY,
    author_id       INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    district_id     INTEGER NOT NULL REFERENCES districts(id),
    title           TEXT NOT NULL,
    description     TEXT NOT NULL,
    role            TEXT NOT NULL,
    status          TEXT NOT NULL DEFAULT 'open',
    matched_user_id INTEGER REFERENCES users(id) ON DELETE SET NULL,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    -- practice-only mirror of the primary subject; the web app ignores it.
    -- Lets analysis.py's `SELECT request FROM requests;` return subjects.
    request         TEXT
);

CREATE TABLE request_tags (
    id          SERIAL PRIMARY KEY,
    request_id  INTEGER NOT NULL REFERENCES requests(id) ON DELETE CASCADE,
    tag_id      INTEGER NOT NULL REFERENCES tags(id) ON DELETE CASCADE
);

CREATE TABLE reports (
    id               SERIAL PRIMARY KEY,
    reporter_id      INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    reported_user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    reason           TEXT NOT NULL,
    description      TEXT,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE blocks (
    id              SERIAL PRIMARY KEY,
    blocker_id      INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    blocked_user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (blocker_id, blocked_user_id)
);

-- Practice table used by Python/get_questions.py and find_matches.py
CREATE TABLE questions (
    id                       SERIAL PRIMARY KEY,
    student_id               INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    subject                  TEXT NOT NULL,
    topic                    TEXT,
    preferred_time           TEXT,
    preferred_language       TEXT,
    preferred_teaching_style TEXT,
    message                  TEXT,
    created_at               TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- One row per (user, weekly time slot); mirrors users.available_times
CREATE TABLE schedules (
    id         SERIAL PRIMARY KEY,
    user_id    INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    slot       TEXT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (user_id, slot)
);

-- ------------------------------------------------------------- districts --

-- ------------------------------------------------------------------ tags --

-- ----------------------------------------------------------------- users --
-- 1000 users: ids 1-500 mentee, 501-950 mentor, 951-1000 both.
-- Every password_hash is bcrypt('Password123!').




















-- -------------------------------------------------------------- requests --















-- ---------------------------------------------------------- request_tags --














-- ------------------------------------------------------------- questions --















-- ------------------------------------------------------------- schedules --































-- ---------------------------------------------------------------- blocks --

-- --------------------------------------------------------------- reports --

-- ----------------------------------------------------------------- views --

-- Lets student analytics code run `SELECT mentor FROM mentors;`
CREATE VIEW mentors AS
SELECT id AS mentor_id,
       name AS mentor,
       subjects,
       location,
       available_times,
       languages,
       grade_level,
       teaching_style,
       district_id
FROM users
WHERE role IN ('mentor', 'both');

-- Lets student scheduling code run `SELECT schedules FROM schedules_db;`
CREATE VIEW schedules_db AS
SELECT s.slot AS schedules,
       s.user_id,
       u.name,
       u.role
FROM schedules s
JOIN users u ON u.id = s.user_id;

-- --------------------------------------------------------------- indexes --

CREATE INDEX idx_users_district      ON users (district_id);
CREATE INDEX idx_users_role          ON users (role);
CREATE INDEX idx_requests_author     ON requests (author_id);
CREATE INDEX idx_requests_district   ON requests (district_id);
CREATE INDEX idx_requests_status     ON requests (status);
CREATE INDEX idx_request_tags_req    ON request_tags (request_id);
CREATE INDEX idx_request_tags_tag    ON request_tags (tag_id);
CREATE INDEX idx_reports_reported    ON reports (reported_user_id);
CREATE INDEX idx_blocks_blocker      ON blocks (blocker_id);
CREATE INDEX idx_blocks_blocked      ON blocks (blocked_user_id);
CREATE INDEX idx_questions_student   ON questions (student_id);
CREATE INDEX idx_schedules_user      ON schedules (user_id);
CREATE INDEX idx_schedules_slot      ON schedules (slot);

-- ------------------------------------------------------- sequence resets --

SELECT setval(pg_get_serial_sequence('districts', 'id'),    (SELECT MAX(id) FROM districts));
SELECT setval(pg_get_serial_sequence('tags', 'id'),         (SELECT MAX(id) FROM tags));
SELECT setval(pg_get_serial_sequence('users', 'id'),        (SELECT MAX(id) FROM users));
SELECT setval(pg_get_serial_sequence('requests', 'id'),     (SELECT MAX(id) FROM requests));
SELECT setval(pg_get_serial_sequence('request_tags', 'id'), (SELECT MAX(id) FROM request_tags));
SELECT setval(pg_get_serial_sequence('reports', 'id'),      (SELECT MAX(id) FROM reports));
SELECT setval(pg_get_serial_sequence('blocks', 'id'),       (SELECT MAX(id) FROM blocks));
SELECT setval(pg_get_serial_sequence('questions', 'id'),    (SELECT MAX(id) FROM questions));
SELECT setval(pg_get_serial_sequence('schedules', 'id'),    (SELECT MAX(id) FROM schedules));

COMMIT;

